+func FetchHomeFeed(
+	ctx context.Context,
+	cookies CookieBundle,
+	max int,
+	pageSize int,
+) ([]MediaItem, error) {
+	if max == 0 {
+		max = -1
+	}
+	if pageSize <= 0 {
+		pageSize = 50
+	}
+	if pageSize > 50 {
+		pageSize = 50
+	}
+
+	out := make([]MediaItem, 0, pageSize)
+	seen := map[string]struct{}{}
+	appendUnique := func(items []MediaItem) {
+		for _, item := range items {
+			if item.URL == "" {
+				continue
+			}
+			if _, ok := seen[item.URL]; ok {
+				continue
+			}
+			seen[item.URL] = struct{}{}
+			out = append(out, item)
+		}
+	}
+
+	maxID := ""
+	pageCount := 0
+	for {
+		pageCount++
+		page, err := fetchHomeFeedPage(ctx, maxID, pageSize, cookies)
+		if err != nil {
+			return out, err
+		}
+		appendUnique(page.items)
+		if max > 0 && len(out) >= max {
+			return out[:max], nil
+		}
+		if !page.moreAvailable || page.nextMaxID == "" {
+			break
+		}
+		if page.nextMaxID == maxID {
+			break
+		}
+		maxID = page.nextMaxID
+		if pageCount > 200 {
+			break
+		}
+	}
+
+	return out, nil
+}
